-- ── Internal state ────────────────────────────────────────────────────────────
local reported         = {}     -- ap_id -> true once returned from poll()
local server_locations = nil    -- set of ap_ids the server expects (nil = all)
local rom_ok           = nil    -- cached "D3" header result
local mem              = {}
local log_fn           = nil

-- ── Logging ───────────────────────────────────────────────────────────────────
local function log(msg)
  if log_fn then pcall(log_fn, "[dkc3] " .. tostring(msg)) end
end

-- ── Memory API (resolved at init; 2-arg domain form + current-domain fallback) ─
local function resolve_memory_api()
  if not memory then return false end
  mem.read_u8  = memory.read_u8 or memory.readbyte
  return mem.read_u8 ~= nil
end

local function read_wram_u8(off)
  if not mem.read_u8 then return nil end
  local ok, v = pcall(mem.read_u8, off, WRAM)
  if ok and type(v) == "number" then return v end
  ok, v = pcall(mem.read_u8, off)                 -- older API: current domain
  if ok and type(v) == "number" then return v end
  return nil
end

-- CARTROM reads with "ROM" / "System Bus" domain-name fallbacks (cores vary;
-- the raw-file-offset CARTROM/ROM form is what every SNES BizHawk core exposes).
local function read_cartrom_u8(off)
  local ok, v = pcall(mem.read_u8, off, CARTROM)
  if ok and type(v) == "number" then return v end
  ok, v = pcall(mem.read_u8, off, "ROM")
  if ok and type(v) == "number" then return v end
  ok, v = pcall(mem.read_u8, off, "System Bus")
  if ok and type(v) == "number" then return v end
  return nil
end

local function bit_and(a, b)
  -- 16-bit safe AND without the bit library (cores vary).
  local res, bitval = 0, 1
  while a > 0 and b > 0 do
    if a % 2 == 1 and b % 2 == 1 then res = res + bitval end
    a = math.floor(a / 2); b = math.floor(b / 2); bitval = bitval * 2
  end
  return res
end

-- ── ROM identity: the LoROM header title starts with "D3" (validate_rom) ───────
local function rom_is_ap()
  if rom_ok ~= nil then return rom_ok end
  local sig = "D3"
  for i = 1, #sig do
    local b = read_cartrom_u8(ROMHASH_OFF + i - 1)
    if b == nil then return false end          -- not readable yet; retry next poll
    if b ~= string.byte(sig, i) then
      rom_ok = false
      log("non-DKC3 ROM (no 'D3' header) — detection idle, no reports")
      return false
    end
  end
  rom_ok = true
  log("DKC3 ROM verified ('D3' header title present)")
  return true
end

-- ── Multiworld context ────────────────────────────────────────────────────────
local function load_locations(ids)
  if type(ids) ~= "table" then return end
  server_locations = {}
  local n = 0
  for _, id in ipairs(ids) do
    local v = tonumber(id)
    if v then server_locations[v] = true; n = n + 1 end
  end
  log("server location set: " .. n .. " ids")
end

local function wanted(ap_id)
  if server_locations == nil then return true end   -- no set provided → report all
  return server_locations[ap_id] == true
end

-- ── Per-poll snapshot of the single flag block (read once, like game_watcher) ──
local flags = nil   -- 0-indexed byte table of the 0x81-byte block

local function refresh_flags()
  flags = {}
  for i = 0, FLAGS_LEN - 1 do flags[i] = read_wram_u8(FLAGS_BASE_OFF + i) end
end

-- A save file is loaded? (game_watcher's first gate; mirrors validate save name.)
local function save_loaded()
  local b0 = read_wram_u8(SAVE_NAME_OFF)
  if b0 == nil or b0 == SAVE_EMPTY_BYTE then return false end
  -- all-0x55 → uninitialised slot.
  local all_uninit = true
  for i = 0, SAVE_NAME_LEN - 1 do
    local b = read_wram_u8(SAVE_NAME_OFF + i)
    if b ~= SAVE_UNINIT then all_uninit = false; break end
  end
  return not all_uninit
end

-- One location's "checked?" test (mirrors game_watcher's bit math exactly).
--   data = flags[off]; bit_set = (data & (1<<bit)) ~= 0; invert = entry[3]
--   checked when bit_set ~= invert
local function location_checked(off, bit, invert)
  if flags == nil then return false end
  local data = flags[off]
  if data == nil then return false end
  local bit_set    = bit_and(data, 2 ^ bit) ~= 0
  local invert_bit = (invert == 1)
  return bit_set ~= invert_bit
end

-- ── Module contract ───────────────────────────────────────────────────────────
function M.init(ctx)
  if ctx and type(ctx.log) == "function" then log_fn = ctx.log end
  if not resolve_memory_api() then
    log("BizHawk memory API unavailable — module idle")
    ADDRESSES_VERIFIED = false
    return
  end
  local cfg = (ctx and ctx.config) or {}
  load_locations(cfg.locations)
  -- Optional: honour the seed's goal carrier if slot_data exposed it.
  local g = cfg.goal
  if g == nil and type(cfg.slot_data) == "table" then g = cfg.slot_data.goal end
  local gv = tonumber(g)
  if gv == GOAL_OPT_KNAUTILUS or gv == GOAL_OPT_BBHUNT then selected_goal = gv end
  local n = 0; for _ in pairs(LOC) do n = n + 1 end
  log("ready: " .. n .. " location flags; goal="
      .. (selected_goal == nil and "either-carrier" or tostring(selected_goal))
      .. " (items_handling=0b111; receive_item is a documented no-op pending "
      .. "in-emulator verification)")
end

function M.poll()
  local new = {}
  if not ADDRESSES_VERIFIED then return new end
  if not rom_is_ap() then return new end
  if not save_loaded() then return new end        -- game_watcher's no-save gate
  refresh_flags()
  for ap_id, ld in pairs(LOC) do
    if not reported[ap_id] and wanted(ap_id)
       and location_checked(ld[1], ld[2], ld[3]) then
      reported[ap_id] = true
      new[#new + 1] = ap_id
    end
  end
  return new
end

function M.is_goal_complete()
  if not ADDRESSES_VERIFIED or not rom_is_ap() then return false end
  if not save_loaded() then return false end
  refresh_flags()
  if flags == nil then return false end
  local function carrier_set(off, bit)
    local d = flags[off]
    return d ~= nil and bit_and(d, 2 ^ bit) ~= 0
  end
  local knautilus = carrier_set(GOAL_KNAUTILUS_OFF, GOAL_KNAUTILUS_BIT)
  local bbhunt    = carrier_set(GOAL_BBHUNT_OFF,    GOAL_BBHUNT_BIT)
  if selected_goal == GOAL_OPT_KNAUTILUS then return knautilus end
  if selected_goal == GOAL_OPT_BBHUNT    then return bbhunt end
  return knautilus or bbhunt              -- unknown goal → either carrier completes
end

-- Remote multiworld items: see the file header. items_handling = 0b111 (FULL
-- remote) means the dkc3 client owns ALL item delivery — a recv-index handshake
-- at DKC3_RECV_PROGRESS_ADDR, per-item count increments at item_rom_data WRAM
-- offsets, the Bear/Swanky/Boomer coin-display pokes, the Patch & Skis
-- progressive-boat upgrade state machine, and the Victory CLIENT_GOAL trigger,
-- all heavily gated on live game state. That path is the one piece deferred until
-- it can be confirmed in-emulator. No-op (never a wrong write) until then; checks
-- + goal above are fully functional.
function M.receive_item(item_id, meta)
  -- intentionally empty (documented)
end

return M
